solution: ```class Solution {
    public boolean reorderedPowerOf2(int n) {
        int[] target = digitCount(n);
        for (int p = 1; p <= 1_000_000_000; p <<= 1) {
            if (Arrays.equals(target, digitCount(p))) return true;
        }
        return false;
    }
    private int[] digitCount(int num) {
        int[] cnt = new int[10];
        while (num > 0) {
            cnt[num % 10]++;
            num /= 10;
        }
        return cnt;
    }
}
